1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteInput {
13	  customer: Customer;
14	  items: Item[];
15	}
16	
17	export interface QuoteContext {
18	  isFollowUp?: boolean;
19	}
20	
21	export interface Damage {
22	  itemType: string;
23	  amount: number;
24	}
25	
26	export interface Incident {
27	  cause: string;
28	  damages: Damage[];
29	}
30	
31	export interface Policy {
32	  items: Item[];
33	  remainingCap: number;
34	}
35	
36	export interface ClaimResult {
37	  payout: number;
38	  remainingCap: number;
39	}
40	
41	const PROCESSING_FEE = 5;
42	const BLOCK_SIZE = 3;
43	const COMPONENT_UNIT_PREMIUM = 25;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	const FIRST_INSURANCE_RATE = 0.1;
46	const LOYALTY_RATE = 0.2;
47	const LOYALTY_MIN_YEARS = 2;
48	const FOLLOW_UP_RATE = 0.15;
49	const CURSE_SURCHARGE_RATE = 0.5;
50	const HIGH_ENCHANTMENT_RATE = 0.3;
51	const HIGH_ENCHANTMENT_THRESHOLD = 5;
52	const DEDUCTIBLE = 100;
53	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
54	const DAMAGE_REIMBURSEMENT_RATE = 0.5;
55	const DRAGON_MATERIAL = "dragon";
56	
57	const COMPONENT_TYPES = ["rune", "moonstone"];
58	
59	const BASE_PREMIUMS: Record<string, number> = {
60	  sword: 100,
61	  amulet: 60,
62	  staff: 80,
63	  potion: 40,
64	  rune: COMPONENT_UNIT_PREMIUM,
65	  moonstone: COMPONENT_UNIT_PREMIUM,
66	};
67	
68	const isComponent = (item: Item): boolean =>
69	  COMPONENT_TYPES.includes(item.type);
70	
71	const isMainItem = (item: Item): boolean => !isComponent(item);
72	
73	const unitPriceFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
74	
75	const sumOver = (items: Item[], valueOf: (item: Item) => number): number =>
76	  items.reduce((sum, item) => sum + valueOf(item), 0);
77	
78	const componentGroupPremium = (count: number): number =>
79	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
80	
81	const countByType = (items: Item[]): Map<string, number> =>
82	  items.reduce((counts, item) => {
83	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
84	    return counts;
85	  }, new Map<string, number>());
86	
87	const componentsBasePremium = (items: Item[]): number =>
88	  [...countByType(items.filter(isComponent)).values()].reduce(
89	    (sum, count) => sum + componentGroupPremium(count),
90	    0
91	  );
92	
93	const mainItemsBasePremium = (items: Item[]): number =>
94	  sumOver(items.filter(isMainItem), unitPriceFor);
95	
96	const totalBasePremium = (items: Item[]): number =>
97	  mainItemsBasePremium(items) + componentsBasePremium(items);
98	
99	const isHighlyEnchanted = (item: Item): boolean =>
100	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
101	
102	const itemSurchargeRate = (item: Item): number =>
103	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
104	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
105	
106	const itemSurcharges = (item: Item): number =>
107	  unitPriceFor(item) * itemSurchargeRate(item);
108	
109	const totalSurcharges = (items: Item[]): number =>
110	  sumOver(items, itemSurcharges);
111	
112	const firstInsuranceSurcharge = (policyBase: number): number =>
113	  policyBase * FIRST_INSURANCE_RATE;
114	
115	const isLoyal = (customer: Customer): boolean =>
116	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
117	
118	const policyBaseShareWhen = (
119	  policyBase: number,
120	  applies: boolean,
121	  rate: number
122	): number => (applies ? policyBase * rate : 0);
123	
124	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
125	  policyBaseShareWhen(policyBase, isLoyal(customer), LOYALTY_RATE);
126	
127	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
128	  policyBaseShareWhen(policyBase, isFollowUp, FOLLOW_UP_RATE);
129	
130	const policyWideAdjustment = (
131	  policyBase: number,
132	  customer: Customer,
133	  isFollowUp: boolean
134	): number =>
135	  firstInsuranceSurcharge(policyBase) -
136	  loyaltyDiscount(policyBase, customer) -
137	  followUpDiscount(policyBase, isFollowUp);
138	
139	const roundPremiumInMHPCOsFavor = (premium: number): number =>
140	  Math.ceil(premium);
141	
142	export const quote = (input: QuoteInput, context: QuoteContext = {}): number => {
143	  const policyBase = totalBasePremium(input.items);
144	  const premiumBeforeFee =
145	    policyBase +
146	    totalSurcharges(input.items) +
147	    policyWideAdjustment(policyBase, input.customer, context.isFollowUp ?? false);
148	  return roundPremiumInMHPCOsFavor(premiumBeforeFee + PROCESSING_FEE);
149	};
150	
151	const isHighEnchantmentClaim = (item: Item): boolean =>
152	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
153	
154	const isDragonMaterial = (item: Item): boolean =>
155	  item.material === DRAGON_MATERIAL;
156	
157	const reimbursedAmount = (item: Item, amount: number): number =>
158	  isHighEnchantmentClaim(item) ? amount * DAMAGE_REIMBURSEMENT_RATE : amount;
159	
160	const damagePayout = (item: Item, damage: Damage): number =>
161	  Math.max(0, reimbursedAmount(item, damage.amount) - DEDUCTIBLE);
162	
163	const damagedItem = (items: Item[], damage: Damage): Item | undefined =>
164	  items.find((item) => item.type === damage.itemType);
165	
166	const totalPayout = (policy: Policy, damages: Damage[]): number =>
167	  damages.reduce((sum, damage) => {
168	    const item = damagedItem(policy.items, damage);
169	    return sum + (item ? damagePayout(item, damage) : 0);
170	  }, 0);
171	
172	export const claim = (policy: Policy, incident: Incident): ClaimResult => {
173	  const payout = totalPayout(policy, incident.damages);
174	  return { payout, remainingCap: policy.remainingCap - payout };
175	};
